body:
I'm trying to use an output port that's an unpacked array and all the output values are `xxxx`.
I'm using the following test bench compiled with `iverilog test.sv -o test -g2012`. 

```systemverilog
`default_nettype none
`timescale 1 ns / 100 ps

module test_tb;

	// Signals
	logic rst = 1;
	logic clk = 0;

	logic [15:0] out_data [0:3];

	// Setup recording
	initial begin
		$dumpfile("test_tb.vcd");
		$dumpvars(0,test_tb);
	end

	// Reset pulse
	initial begin
		# 201 rst = 0;
		# 65000 $finish;
	end

	// Clock
	always #5 clk = !clk;

	// DUT
	test dut_I (
		.out_data(out_data),
		.clk(clk),
		.rst(rst)
	);

	// Show result
	always @(posedge clk)
		if (~rst)
			$display("%x", out_data[0]);

endmodule // test_tb


module test (
	output logic [15:0] out_data [0:3],
	input wire clk,
	input wire rst
);

	logic [15:0] cnt;

	assign out_data[0] = cnt;
	assign out_data[1] = cnt + 1;
	assign out_data[2] = cnt + 2;
	assign out_data[3] = cnt + 3;

	always @(posedge clk)
		if (rst)
			cnt <= 0;
		else
			cnt <= cnt + 1;

endmodule // test
```

